return [{ json: { sourceBatch: 'portfolio-fleet-demo-001', records: [
  { registration_plate: 'N8N-1024', company: 'DemoRent', vehicle_group: 'Compact', model: 'Toyota Yaris Hybrid', wash_type: 'standard', eco: true, current_status: 'available', maintenance_flag: false, damage_flag: false, fuel_level: 88, current_location: 'Athens Station A', assigned_employee: 'station-demo-01', notes: 'Clean and ready' },
  { registration_plate: 'OPS-2048', company: 'DemoRent', vehicle_group: 'SUV', model: 'Kia Sportage', wash_type: 'deep', eco: false, current_status: 'inspection', maintenance_flag: true, damage_flag: false, fuel_level: 41, current_location: 'Athens Service Bay', assigned_employee: 'station-demo-02', notes: 'Maintenance light reported' },
  { registration_plate: 'QA-4096', company: 'PartnerFleet', vehicle_group: 'Van', model: 'Mercedes Vito', wash_type: 'deep', eco: false, current_status: 'blocked', maintenance_flag: false, damage_flag: true, fuel_level: 22, current_location: 'Athens Station B', assigned_employee: 'station-demo-03', notes: 'Damage photo required before release' }
] } }];

const sourceBatch = $json.sourceBatch || 'manual-fleet-batch';
const records = Array.isArray($json.records) ? $json.records : [];
const validRecords = [];
const rejectedRecords = [];
for (const record of records) {
  const missing = ['registration_plate', 'company', 'model', 'current_status'].filter((field) => !record[field]);
  if (missing.length) {
    rejectedRecords.push({ rejection_reason: `missing_required_fields:${missing.join(',')}`, raw_record: record });
  } else {
    validRecords.push(record);
  }
}
return [{ json: { sourceBatch, recordsSeen: records.length, validRecords, rejectedRecords } }];

const seen = new Set();
let duplicateCandidates = 0;
const normalizedRecords = ($json.validRecords || []).map((record) => {
  const registration_plate = String(record.registration_plate).toUpperCase().replace(/[^A-Z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
  if (seen.has(registration_plate)) duplicateCandidates += 1;
  seen.add(registration_plate);
  return { ...record, registration_plate, company: String(record.company).trim(), model: String(record.model).trim(), source_batch: $json.sourceBatch, raw_record: record };
});
return [{ json: { ...$json, validRecords: normalizedRecords, duplicateCandidates } }];

const priorityRank = { NORMAL: 1, MEDIUM: 2, HIGH: 3 };
let highPriorityCount = 0;
const enriched = ($json.validRecords || []).map((record) => {
  let operational_priority = 'NORMAL';
  const status = String(record.current_status || '').toLowerCase();
  if (record.damage_flag || record.maintenance_flag || status === 'blocked' || Number(record.fuel_level || 0) < 25) operational_priority = 'HIGH';
  else if (String(record.wash_type || '').toLowerCase() === 'deep' || Number(record.fuel_level || 0) < 50 || status === 'inspection') operational_priority = 'MEDIUM';
  if (priorityRank[operational_priority] === priorityRank.HIGH) highPriorityCount += 1;
  return { ...record, operational_priority };
});
return [{ json: { ...$json, validRecords: enriched, recordsValid: enriched.length, recordsRejected: ($json.rejectedRecords || []).length, highPriorityCount } }];

const summary = {
  sourceBatch: $json.sourceBatch,
  recordsSeen: $json.recordsSeen,
  recordsValid: $json.recordsValid,
  recordsRejected: $json.recordsRejected,
  duplicateCandidates: $json.duplicateCandidates,
  highPriorityCount: $json.highPriorityCount,
  validRecords: $json.validRecords,
  rejectedRecords: $json.rejectedRecords
};
return [{ json: summary }];

