INSERT INTO public.fleet_operation_runs (
  source_batch, records_seen, records_valid, records_rejected,
  duplicate_candidates, high_priority_count, status, summary
) VALUES ($1, $2, $3, $4, $5, $6, 'completed', $7::jsonb)
RETURNING id, source_batch, status, created_at;

